arguments.argument:
if global.gamePaused=false
{
  makeEnemyActive(0)
  if bActive=true and stunnedTime=0
  {
    //---------- Movement ----------
    moveTime+=1
    if moveTime>=45
    {
      xVel*=-1
      moveTime=irandom(5)
    }
    
    if throwTime<throwDelay
    {
      if x>oPlayer1.x
        image_xscale=-1
      else
        image_xscale=1
    }
    
    //---------- Throw hammerang ----------
    throwTime+=1
    if throwTime>=throwDelay
    {
      if throwTime=throwDelay //change anim
        sprite_index=sDoomknockerThrow
      else if throwTime=throwDelay+6 //Throw hammerang
      {
        var tNewAttack;
        tNewAttack=instance_create(x-(4*image_xscale),y-24,oDoomknockerHammerang)
        tNewAttack.image_xscale=image_xscale
        tNewAttack.atkPower=atkPower
        tNewAttack.bulletSpeed=5*image_xscale
        if random(10)>5
        {
          y-=2
          yVel=-2
        }
        sprite_index=sDoomknockerWalk
        throwTime=0
      }
    }
    
    yVel+=0.2
    if isCollisionBottom(1)
      yVel=0
    if isCollisionLeft(1)
      xVel=runAcc
    if isCollisionRight(1)
      xVel=-runAcc
    if isCollisionSolid()
      y-=2
    
    moveTo(xVel,yVel)
    if y>room_height+24
      instance_destroy()
  }
  enemyStepEvent()
}
